VALUES
  ('elementary-f29af906-moex-00368', 'elementary-f29af906', 'elementary-f29af906-moex-113-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依土地徵收條例之規定，有關協議價購之敘述，下列何者正確？', '["於協議價購時，若依其他法律享有優先購買權者，得主張優先購買", "開闢交通路線因具有高度公共利益，故得不與所有權人協議而逕行徵收", "協議價購性質上屬於代替行政處分之行政契約，如有違法得予撤銷", "協議價購為土地徵收之法定先行程序，如應踐行而未踐行此程序，其徵收處分構成違法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "17c8e929e785", "answer_pdf_sha1": "120c8cc2fa96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00369', 'elementary-f29af906', 'elementary-f29af906-moex-113-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依土地徵收條例第10條之規定，需用土地人於事業計畫報請目的事業主管機關許可前，應舉行公聽會， 聽取土地所有權人及利害關係人之意見。有關該公聽會之敘述，下列何者正確？', '["該公聽會應作成決議，並有拘束各關係機關之效力", "土地所有權人若決定不出席，則該公聽會應屬無效", "利害關係人之意見僅供參考，非必然拘束主管機關", "公聽會進行程序，應依行政程序法有關聽證之規定辦理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "17c8e929e785", "answer_pdf_sha1": "120c8cc2fa96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00370', 'elementary-f29af906', 'elementary-f29af906-moex-113-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依土地徵收條例之規定，有關撤銷或廢止徵收之敘述，下列何者錯誤？', '["撤銷或廢止徵收，由需用土地人向中央主管機關申請之", "撤銷或廢止徵收之土地或土地改良物，其已一併徵收之殘餘部分，已移轉或另有他用者，無須同時辦理 撤銷或廢止", "因工程變更設計，致原徵收之土地不在工程用地範圍內者，應撤銷徵收", "已依徵收計畫開始使用，尚未依徵收計畫完成使用之土地，因情事變更，致原徵收土地之全部或一部已 無徵收之必要者，應廢止徵收"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "17c8e929e785", "answer_pdf_sha1": "120c8cc2fa96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00371', 'elementary-f29af906', 'elementary-f29af906-moex-113-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依離島建設條例規定，主管機關公告於該條例適用地區之戰地政務期間徵收之土地，如管理機關已無使用 事實，原土地所有權人得申請購回其土地。關於該公告之敘述，下列何者正確？', '["該公告須刊登政府公報或新聞紙，始生效力", "該公告之性質為一般處分", "不服該公告之利害關係人得提起訴願", "該公告為事實行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "17c8e929e785", "answer_pdf_sha1": "120c8cc2fa96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00372', 'elementary-f29af906', 'elementary-f29af906-moex-113-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '關於行政機關或行政處分之相對人不得主張公法上不當得利返還請求權，下列何者正確？', '["土地所有權人因行政機關計算有誤，而溢領土地徵收補償金時", "締結行政契約後，依契約受有給付時，嗣後行政機關發現契約締結時有無效之事由", "依安置計畫已核發中低收入戶之租金補貼，租金補貼之處分經廢止而向將來失效時", "徵收土地改良物時，行政機關錯認法條規定情形而誤發多餘遷移費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "17c8e929e785", "answer_pdf_sha1": "120c8cc2fa96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00373', 'elementary-f29af906', 'elementary-f29af906-moex-113-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依行政程序法規定，公法上請求權之時效完成後，其法律效果為下列何者？', '["時效完成，權利消滅", "時效完成，訴權消滅，權利不受影響", "時效完成，得轉換為私法上請求權，適用民法規定", "時效完成，抗辯權發生，權利不受影響"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "17c8e929e785", "answer_pdf_sha1": "120c8cc2fa96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00374', 'elementary-f29af906', 'elementary-f29af906-moex-113-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '公物係直接供公共目的使用，下列何者不是公物之特性？', '["不融通性", "不得為強制執行標的", "不得徵收", "適用取得時效之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "17c8e929e785", "answer_pdf_sha1": "120c8cc2fa96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00375', 'elementary-f29af906', 'elementary-f29af906-moex-113-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '行政行為之手段與目的之間必須合乎一定比例，下列敘述何者非比例原則之概念？', '["行政行為應合適且有助於目的之達成", "就多種合適方法中，應選擇最可能對人民權益傷害最小的方法行之", "行政行為只要合乎合適性、必要性原則，雖導致第三人付出過重的不利代價，亦得為之", "比例原則是源自於法治國家原則，並具有憲法位階"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "17c8e929e785", "answer_pdf_sha1": "120c8cc2fa96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00376', 'elementary-f29af906', 'elementary-f29af906-moex-113-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '內政部針對土地法規疑義所為之函釋，此函釋之法律性質為何？', '["法規命令", "行政規則", "行政處分", "行政指導"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "17c8e929e785", "answer_pdf_sha1": "120c8cc2fa96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00377', 'elementary-f29af906', 'elementary-f29af906-moex-113-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '行政行為應保護人民正當合理之信賴，下列敘述何者非信賴保護原則之概念？', '["經廢止或變更之行政法規有重大明顯違反上位規範者，亦有信賴保護原則之適用", "信賴保護原則之適用，必須具備有信賴基礎，即行政機關有令人民信賴之行政行為", "客觀上有具體的信賴表現行為，且信賴表現與信賴基礎間必須有因果關係", "當事人之信賴必須值得保護"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "17c8e929e785", "answer_pdf_sha1": "120c8cc2fa96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
